public class FilterCalcMergeRule extends RelOptRule { public static final FilterCalcMergeRule INSTANCE = new FilterCalcMergeRule ( RelFactories . LOGICAL_BUILDER ) ; public FilterCalcMergeRule ( RelBuilderFactory relBuilderFactory ) { super ( operand ( Filter . class , operand ( LogicalCalc . class , any ( ) ) ) , relBuilderFactory , null ) ; } public void onMatch ( RelOptRuleCall call ) { final LogicalFilter filter = call . rel ( 0 ) ; final LogicalCalc calc = call . rel ( 1 ) ; if ( calc . getProgram ( ) . containsAggs ( ) ) { return ; } final RexBuilder rexBuilder = filter . getCluster ( ) . getRexBuilder ( ) ; final RexProgramBuilder progBuilder = new RexProgramBuilder ( calc . getRowType ( ) , rexBuilder ) ; progBuilder . addIdentity ( ) ; progBuilder . addCondition ( filter . getCondition ( ) ) ; RexProgram topProgram = progBuilder . getProgram ( ) ; RexProgram bottomProgram = calc . getProgram ( ) ; RexProgram mergedProgram = RexProgramBuilder . mergePrograms ( topProgram , bottomProgram , rexBuilder ) ; final LogicalCalc newCalc = LogicalCalc . create ( calc . getInput ( ) , mergedProgram ) ; call . transformTo ( newCalc ) ; } }